import React, { useEffect, useMemo, useState } from 'react';
import { SafeAreaView, View, Text, TouchableOpacity, StyleSheet, ActivityIndicator, Alert, ScrollView } from 'react-native';
import * as AuthSession from 'expo-auth-session';
import * as SecureStore from 'expo-secure-store';

const OAUTH_CONFIG = {
  authorizationEndpoint: 'https://your-auth-server.example.com/oauth/authorize',
  tokenEndpoint: 'https://your-auth-server.example.com/oauth/token',
  revocationEndpoint: 'https://your-auth-server.example.com/oauth/revoke',
  clientId: 'mobile_app_client_123',
  redirectUri: AuthSession.makeRedirectUri({ useProxy: true }),
  scopes: ['openid', 'profile', 'email'],
};

const TOKEN_KEYS = {
  accessToken: 'access_token',
  refreshToken: 'refresh_token',
  idToken: 'id_token',
  expiry: 'token_expiry',
};

export default function App() {
  const [authState, setAuthState] = useState({
    accessToken: null,
    refreshToken: null,
    idToken: null,
    expiry: null,
    loading: true,
  });

  const discovery = useMemo(
    () => ({
      authorizationEndpoint: OAUTH_CONFIG.authorizationEndpoint,
      tokenEndpoint: OAUTH_CONFIG.tokenEndpoint,
      revocationEndpoint: OAUTH_CONFIG.revocationEndpoint,
    }),
    []
  );

  const [request, response, promptAsync] = AuthSession.useAuthRequest(
    {
      clientId: OAUTH_CONFIG.clientId,
      redirectUri: OAUTH_CONFIG.redirectUri,
      scopes: OAUTH_CONFIG.scopes,
      responseType: AuthSession.ResponseType.Code,
      usePKCE: true,
    },
    discovery
  );

  useEffect(() => {
    loadTokens();
  }, []);

  useEffect(() => {
    if (response?.type === 'success') {
      const code = response.params?.code;
      const codeVerifier = request?.codeVerifier;
      if (code && codeVerifier) {
        exchangeCodeForToken(code, codeVerifier);
      }
    }
  }, [response]);

  const loadTokens = async () => {
    try {
      const [accessToken, refreshToken, idToken, expiry] = await Promise.all([
        SecureStore.getItemAsync(TOKEN_KEYS.accessToken),
        SecureStore.getItemAsync(TOKEN_KEYS.refreshToken),
        SecureStore.getItemAsync(TOKEN_KEYS.idToken),
        SecureStore.getItemAsync(TOKEN_KEYS.expiry),
      ]);

      setAuthState({
        accessToken,
        refreshToken,
        idToken,
        expiry,
        loading: false,
      });
    } catch (e) {
      setAuthState((prev) => ({ ...prev, loading: false }));
    }
  };

  const saveTokens = async (tokenResponse) => {
    const expiry = tokenResponse.expires_in
      ? String(Date.now() + tokenResponse.expires_in * 1000)
      : '';

    await Promise.all([
      SecureStore.setItemAsync(TOKEN_KEYS.accessToken, tokenResponse.access_token || ''),
      SecureStore.setItemAsync(TOKEN_KEYS.refreshToken, tokenResponse.refresh_token || ''),
      SecureStore.setItemAsync(TOKEN_KEYS.idToken, tokenResponse.id_token || ''),
      SecureStore.setItemAsync(TOKEN_KEYS.expiry, expiry),
    ]);

    setAuthState({
      accessToken: tokenResponse.access_token || null,
      refreshToken: tokenResponse.refresh_token || null,
      idToken: tokenResponse.id_token || null,
      expiry: expiry || null,
      loading: false,
    });
  };

  const clearTokens = async () => {
    await Promise.all([
      SecureStore.deleteItemAsync(TOKEN_KEYS.accessToken),
      SecureStore.deleteItemAsync(TOKEN_KEYS.refreshToken),
      SecureStore.deleteItemAsync(TOKEN_KEYS.idToken),
      SecureStore.deleteItemAsync(TOKEN_KEYS.expiry),
    ]);

    setAuthState({
      accessToken: null,
      refreshToken: null,
      idToken: null,
      expiry: null,
      loading: false,
    });
  };

  const exchangeCodeForToken = async (code, codeVerifier) => {
    try {
      setAuthState((prev) => ({ ...prev, loading: true }));

      const body = new URLSearchParams({
        grant_type: 'authorization_code',
        client_id: OAUTH_CONFIG.clientId,
        code,
        redirect_uri: OAUTH_CONFIG.redirectUri,
        code_verifier: codeVerifier,
      }).toString();

      const res = await fetch(OAUTH_CONFIG.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body,
      });

      const json = await res.json();

      if (!res.ok) {
        throw new Error(json.error_description || json.error || 'Token exchange failed');
      }

      await saveTokens(json);
    } catch (err) {
      setAuthState((prev) => ({ ...prev, loading: false }));
      Alert.alert('Authentication Error', err.message || 'Unable to sign in');
    }
  };

  const refreshAccessToken = async () => {
    if (!authState.refreshToken) {
      Alert.alert('No refresh token', 'Please sign in again.');
      return;
    }

    try {
      setAuthState((prev) => ({ ...prev, loading: true }));

      const body = new URLSearchParams({
        grant_type: 'refresh_token',
        client_id: OAUTH_CONFIG.clientId,
        refresh_token: authState.refreshToken,
      }).toString();

      const res = await fetch(OAUTH_CONFIG.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body,
      });

      const json = await res.json();

      if (!res.ok) {
        throw new Error(json.error_description || json.error || 'Token refresh failed');
      }

      await saveTokens({
        ...json,
        refresh_token: json.refresh_token || authState.refreshToken,
      });
    } catch (err) {
      setAuthState((prev) => ({ ...prev, loading: false }));
      Alert.alert('Refresh Error', err.message || 'Unable to refresh token');
    }
  };

  const signOut = async () => {
    try {
      if (authState.accessToken && OAUTH_CONFIG.revocationEndpoint) {
        const body = new URLSearchParams({
          token: authState.accessToken,
          client_id: OAUTH_CONFIG.clientId,
        }).toString();

        await fetch(OAUTH_CONFIG.revocationEndpoint, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body,
        });
      }
    } catch (_) {
    } finally {
      await clearTokens();
    }
  };

  const isExpired = authState.expiry ? Date.now() > Number(authState.expiry) : false;

  if (authState.loading) {
    return (
      <SafeAreaView style={styles.container}>
        <ActivityIndicator size="large" />
        <Text style={styles.loadingText}>Loading...</Text>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      <ScrollView contentContainerStyle={styles.content}>
        <Text style={styles.title}>OAuth 2.0 Mobile App</Text>

        {!authState.accessToken ? (
          <View style={styles.card}>
            <Text style={styles.label}>Status</Text>
            <Text style={styles.value}>Signed out</Text>
            <TouchableOpacity
              style={[styles.button, !request && styles.buttonDisabled]}
              disabled={!request}
              onPress={() => promptAsync({ useProxy: true })}
            >
              <Text style={styles.buttonText}>Sign In</Text>
            </TouchableOpacity>
          </View>
        ) : (
          <View style={styles.card}>
            <Text style={styles.label}>Status</Text>
            <Text style={styles.value}>Signed in</Text>

            <Text style={styles.label}>Access Token</Text>
            <Text selectable style={styles.tokenText}>
              {authState.accessToken}
            </Text>

            <Text style={styles.label}>Refresh Token</Text>
            <Text selectable style={styles.tokenText}>
              {authState.refreshToken || 'N/A'}
            </Text>

            <Text style={styles.label}>ID Token</Text>
            <Text selectable style={styles.tokenText}>
              {authState.idToken || 'N/A'}
            </Text>

            <Text style={styles.label}>Expires</Text>
            <Text style={[styles.value, isExpired && styles.expired]}>
              {authState.expiry ? new Date(Number(authState.expiry)).toLocaleString() : 'Unknown'}
            </Text>

            <TouchableOpacity style={styles.button} onPress={refreshAccessToken}>
              <Text style={styles.buttonText}>Refresh Token</Text>
            </TouchableOpacity>

            <TouchableOpacity style={[styles.button, styles.logoutButton]} onPress={signOut}>
              <Text style={styles.buttonText}>Sign Out</Text>
            </TouchableOpacity>
          </View>
        )}
      </ScrollView>
    </SafeAreaView>
  );
}

